/**
 * @summary Semantic-style full-text search across pages and sources
 */
export const getSearchWorkspaceUrl = (params: SearchWorkspaceParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/search?${stringifiedParams}` : `/api/search`
}

export const searchWorkspace = async (params: SearchWorkspaceParams, options?: RequestInit): Promise<SearchResult[]> => {

  return customFetch<SearchResult[]>(getSearchWorkspaceUrl(params),
  {
    ...options,
    method: 'GET'


  }
);}





